class Solution(object):
    def twoSum(self, numbers, target):
        """
        :type numbers: List[int]
        :type target: int
        :rtype: List[int]
        """
        left, right = 0, len(numbers) - 1

        while left < right:
            current_sum = numbers[left] + numbers[right]

            if current_sum == target:
                return [left + 1, right + 1]  # Return indices as 1-indexed
            elif current_sum < target:
                left += 1
            else:
                right -= 1

        return []  # This line should never be reached due to the problem constraints

regular-expression-matching.solution:
class Solution(object):
    def isMatch(self, s, p):
        """
        :type s: str
        :type p: str
        :rtype: bool
        """
        m, n = len(s), len(p)

        # Initialize the dp table
        dp = [[False] * (n + 1) for _ in range(m + 1)]

        # Base case: empty pattern matches empty string
        dp[0][0] = True

        # Handle patterns with '*' at the beginning
        for j in range(2, n + 1):
            if p[j - 1] == '*':
                dp[0][j] = dp[0][j - 2]

        # Fill the dp table
        for i in range(1, m + 1):
            for j in range(1, n + 1):
                if p[j - 1] == s[i - 1] or p[j - 1] == '.':
                    dp[i][j] = dp[i - 1][j - 1]
                elif p[j - 1] == '*':
                    dp[i][j] = dp[i][j - 2]  # Zero occurrences of the preceding element
                    if p[j - 2] == s[i - 1] or p[j - 2] == '.':
                        dp[i][j] |= dp[i - 1][j]  # One or more occurrences of the preceding element

        return dp[m][n]

create-maximum-number.solution:
class Solution(object):
    def maxNumber(self, nums1, nums2, k):
        """
        :type nums1: List[int]
        :type nums2: List[int]
        :type k: int
        :rtype: List[int]
        """

        def largest_number(nums, m):
            stack = []
            remain = len(nums) - m
            for num in nums:
                while stack and remain > 0 and stack[-1] < num:
                    stack.pop()
                    remain -= 1
                stack.append(num)
            return stack[:m]

        def compare(a, b):
            i, j = 0, 0
            while i < len(a) and j < len(b):
                if a[i] > b[j]:
                    return True
                elif a[i] < b[j]:
                    return False
                i += 1
                j += 1
            return i < len(a)

        res = []
        for i in range(max(0, k - len(nums2)), min(k, len(nums1)) + 1):
            a = largest_number(nums1, i)
            b = largest_number(nums2, k - i)
            if compare(a, b):
                res = max(res, largest_number(a + b, k))
            else:
                res = max(res, largest_number(b + a, k))

        return res

