class Solution(object):
    def searchRange(self, nums, target):
        """
        :type nums: List[int]
        :type target: int
        :rtype: List[int]
        """

        def find_left(nums, target):
            left, right = 0, len(nums) - 1
            result = -1
            while left <= right:
                mid = left + (right - left) // 2
                if nums[mid] == target:
                    result = mid
                    right = mid - 1  # Continue searching in the left half
                elif nums[mid] < target:
                    left = mid + 1
                else:
                    right = mid - 1
            return result

        def find_right(nums, target):
            left, right = 0, len(nums) - 1
            result = -1
            while left <= right:
                mid = left + (right - left) // 2
                if nums[mid] == target:
                    result = mid
                    left = mid + 1  # Continue searching in the right half
                elif nums[mid] < target:
                    left = mid + 1
                else:
                    right = mid - 1
            return result

        left_index = find_left(nums, target)
        if left_index == -1:
            return [-1, -1]

        right_index = find_right(nums, target)

        return [left_index, right_index]

best-time-to-buy-and-sell-stock-iv.solution:
class Solution(object):
    def maxProfit(self, k, prices):
        """
        :type k: int
        :type prices: List[int]
        :rtype: int
        """

        if not prices or k == 0:
            return 0

        # If k is greater than or equal to half the length of prices, we can perform all possible transactions
        if k >= len(prices) // 2:
            return sum(max(prices[i+1] - prices[i], 0) for i in range(len(prices) - 1))

        n = len(prices)
        dp = [[0] * (k + 1) for _ in range(n)]

        for i in range(1, n):
            diff = prices[i] - prices[i - 1]

            for j in range(1, k + 1):
                # Update the dp table
                dp[i][j] = max(dp[i - 1][j], dp[i - 1][j - 1] + diff)

        return dp[-1][-1]

