class Solution(object):
    def containsNearbyDuplicate(self, nums, k):
        """
        :type nums: List[int]
        :type k: int
        :rtype: bool
        """
        # Dictionary to store the last seen index of each number
        seen = {}

        for i, num in enumerate(nums):
            # Check if the number is already in the dictionary
            if num in seen:
                # If it is, check if the difference between the current index and the last seen index is <= k
                if i - seen[num] <= k:
                    return True
            # Update the last seen index of the number
            seen[num] = i

        # If no duplicates within the window are found, return False
        return False

