class Solution(object):
    def removeInvalidParentheses(self, s):
        def isValid(s):
            balance = 0
            for char in s:
                if char == '(':
                    balance += 1
                elif char == ')':
                    balance -= 1
                # If balance is negative, there are more closing parentheses than opening ones
                if balance < 0:
                    return False
            # At the end, balance should be zero for the string to be valid
            return balance == 0

        def dfs(s, index, left_removed, right_removed, path):
            if left_removed + right_removed == len(s):  # All parentheses removed
                if isValid(path):
                    result.add(path)
                return

            for i in range(index, len(s)):
                if i > index and s[i] == s[i - 1]:  # Skip duplicates
                    continue

                if s[i] == '(':
                    dfs(s, i + 1, left_removed + 1, right_removed, path + s[i])
                elif s[i] == ')':
                    dfs(s, i + 1, left_removed, right_removed + 1, path + s[i])
                else:
                    dfs(s, i + 1, left_removed, right_removed, path + s[i])

        result = set()
        dfs(s, 0, 0, 0, "")
        return list(result)

palindrome-partitioning-ii.solution:
class Solution(object):
    def minCut(self, s):
        """
        :type s: str
        :rtype: int
        """
        n = len(s)

        # Initialize a DP table where dp[i] will store the minimum cuts needed for the substring s[0:i+1]
        dp = [float('inf')] * n

        # A helper function to check if a substring is a palindrome
        def is_palindrome(start, end):
            while start < end:
                if s[start] != s[end]:
                    return False
                start += 1
                end -= 1
            return True

        # Fill the DP table
        for i in range(n):
            # Check all possible palindromic substrings ending at position i
            for j in range(i + 1):
                if is_palindrome(j, i):
                    if j == 0:
                        dp[i] = 0  # No cuts needed for an empty string or single character
                    else:
                        dp[i] = min(dp[i], dp[j - 1] + 1)

        return dp[n - 1]

palindrome-pairs.solution:
class Solution(object):
    def palindromePairs(self, words):
        """
        :type words: List[str]
        :rtype: List[List[int]]
        """
        # Helper function to check if a string is a palindrome
        def is_palindrome(s):
            return s == s[::-1]

        # Dictionary to store the indices of words
        word_to_index = {word: i for i, word in enumerate(words)}

        result = []

        # Iterate over each word in the list
        for i, word in enumerate(words):
            n = len(word)

            # Check if the word is empty
            if word == "":
                # Look for words that form palindromes when concatenated with this empty string
                for j in range(n):
                    if is_palindrome(words[j]) and j != i:
                        result.append([i, j])
                        result.append([j, i])

            # Check if the word is a palindrome and not a single character
            elif is_palindrome(word) and n > 1:
                # Look for words that form palindromes when concatenated with the reverse of this word
                for j in range(n):
                    left = word[:j]
                    right = word[j:]
                    if is_palindrome(left) and right in word_to_index:
                        result.append([word_to_index[right], i])
                    if is_palindrome(right) and left in word_to_index:
                        result.append([i, word_to_index[left]])

            # Check for non-empty words
            else:
                # Check if the reverse of the word forms a palindrome
                reversed_word = word[::-1]
                if reversed_word in word_to_index and word_to_index[reversed_word] != i:
                    result.append([word_to_index[reversed_word], i])

                # Check if the word can be split into two parts such that both parts are palindromes
                for j in range(1, n):
                    left = word[:j]
                    right = word[j:]
                    if is_palindrome(left) and right[::-1] in word_to_index:
                        result.append([i, word_to_index[right[::-1]]])
                    if is_palindrome(right) and left[::-1] in word_to_index:
                        result.append([word_to_index[left[::-1]], i])

        return result

