from collections import deque

class Solution(object):
    def containVirus(self, isInfected):
        """
        :type isInfected: List[List[int]]
        :rtype: int
        """
        if not isInfected:
            return 0

        m, n = len(isInfected), len(isInfected[0])
        directions = [(0, 1), (1, 0), (0, -1), (-1, 0)]

        def bfs(x, y, region_id):
            queue = deque([(x, y)])
            visited = {(x, y)}
            region = set()
            walls = 0

            while queue:
                cx, cy = queue.popleft()
                region.add((cx, cy))

                for dx, dy in directions:
                    nx, ny = cx + dx, cy + dy
                    if 0 <= nx < m and 0 <= ny < n and isInfected[nx][ny] == 0:
                        walls += 1
                        queue.append((nx, ny))
                        visited.add((nx, ny))
                    elif 0 <= nx < m and 0 <= ny < n and isInfected[nx][ny] == 1:
                        queue.append((nx, ny))
                        visited.add((nx, ny))

            return region, walls

        def get_neighbors(x, y):
            neighbors = []
            for dx, dy in directions:
                nx, ny = x + dx, y + dy
                if 0 <= nx < m and 0 <= ny < n:
                    neighbors.append((nx, ny))
            return neighbors

        def get_max_threat_and_walls():
            max_threat = 0
            max_walls = float('inf')
            selected_region = None

            for i in range(m):
                for j in range(n):
                    if isInfected[i][j] == 1:
                        region, walls = bfs(i, j, region_id)
                        threat = len(set(get_neighbors(i, j)) & region)
                        if threat > max_threat or (threat == max_threat and walls < max_walls):
                            max_threat = threat
                            max_walls = walls
                            selected_region = region
                            region_id += 1

            return selected_region, max_threat, max_walls

        walls_used = 0
        region_id = 2

        while True:
            selected_region, max_threat, max_walls = get_max_threat_and_walls()
            if not selected_region:
                break

            for x, y in selected_region:
                isInfected[x][y] = -region_id

            walls_used += max_walls

            for x, y in selected_region:
                for dx, dy in directions:
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < m and 0 <= ny < n and isInfected[nx][ny] == 0:
                        isInfected[nx][ny] = -region_id

            for x, y in selected_region:
                isInfected[x][y] = -1

        return walls_used

