class Solution(object):
    def longestIncreasingPath(self, matrix):
        """
        :type matrix: List[List[int]]
        :rtype: int
        """
        if not matrix or not matrix[0]:
            return 0

        rows, cols = len(matrix), len(matrix[0])
        directions = [(0, 1), (1, 0), (-1, 0), (0, -1)]  # Right, Down, Up, Left
        max_length = 0

        # Memoization dictionary to store the longest path length from a cell
        cache = {}

        def dfs(i, j):
            if (i, j) in cache:
                return cache[(i, j)]

            longest_path = 1
            for di, dj in directions:
                ni, nj = i + di, j + dj
                if 0 <= ni < rows and 0 <= nj < cols and matrix[ni][nj] > matrix[i][j]:
                    longest_path = max(longest_path, 1 + dfs(ni, nj))

            cache[(i, j)] = longest_path
            return longest_path

        for i in range(rows):
            for j in range(cols):
                max_length = max(max_length, dfs(i, j))

        return max_length

