class Solution(object):
    def wordBreak(self, s, wordDict):
        """
        :type s: str
        :type wordDict: List[str]
        :rtype: List[str]
        """
        self.memo = {}
        return self.dfs(s, wordDict)

    def dfs(self, s, wordDict):
        if not s:
            return []
        if s in self.memo:
            return self.memo[s]

        result = []
        for i in range(1, len(s) + 1):
            prefix = s[:i]
            if prefix in wordDict:
                suffix = s[i:]
                suffix_sentences = self.dfs(suffix, wordDict)
                if suffix_sentences:
                    for sentence in suffix_sentences:
                        result.append(prefix + ' ' + sentence)

        self.memo[s] = result
        return result

