class Solution(object):
    def majorityElement(self, nums):
        # Initialize candidate and count
        candidate = None
        count = 0

        # Iterate through the array to find the candidate
        for num in nums:
            if count == 0:
                candidate = num
            count += 1 if num == candidate else -1

        # Verify the candidate by counting its occurrences
        count = 0
        for num in nums:
            if num == candidate:
                count += 1

        # Check if the candidate is indeed the majority element
        return candidate if count > len(nums) // 2 else None

