class Solution(object):
    def numberToWords(self, num):
        """
        :type num: int
        :rtype: str
        """
        if num == 0:
            return "Zero"

        below_20 = ["", "One", "Two", "Three", "Four", "Five", "Six", "Seven", "Eight", "Nine", "Ten", "Eleven", "Twelve", "Thirteen", "Fourteen", "Fifteen", "Sixteen", "Seventeen", "Eighteen", "Nineteen"]
        tens = ["", "", "Twenty", "Thirty", "Forty", "Fifty", "Sixty", "Seventy", "Eighty", "Ninety"]

        def helper(n):
            if n < 20:
                return below_20[n]
            elif n < 100:
                return tens[n // 10] + (below_20[n % 10] if n % 10 != 0 else "")
            else:
                return below_20[n // 100] + " Hundred" + (helper(n % 100) if n % 100 != 0 else "")

        billion = helper(num // 1000000000)
        million = helper((num % 1000000000) // 1000000)
        thousand = helper((num % 1000000) // 1000)
        rest = helper(num % 1000)

        result = []
        if billion:
            result.append(billion + " Billion")
        if million:
            result.append(million + " Million")
        if thousand:
            result.append(thousand + " Thousand")
        if rest:
            result.append(rest)

        return " ".join(result).strip()

