class Solution(object):
    def findRedundantDirectedConnection(self, edges):
        """
        :type edges: List[List[int]]
        :rtype: List[int]
        """

        def find(x):
            if uf[x] != x:
                uf[x] = find(uf[x])
            return uf[x]

        def union(x, y):
            root_x = find(x)
            root_y = find(y)
            if root_x != root_y:
                uf[root_x] = root_y

        n = len(edges)
        uf = list(range(n + 1))  # Union-Find array initialized to point to themselves
        parent_count = [0] * (n + 1)  # Array to count the number of parents for each node

        # Find the cycle and the node with multiple parents
        cycle_node = -1
        cycle_edge = None
        multiple_parent_node = -1
        for u, v in edges:
            if parent_count[v] > 0:
                multiple_parent_node = v
            else:
                parent_count[v] += 1
                if find(u) == find(v):
                    cycle_node = v
                    cycle_edge = [u, v]
                else:
                    union(u, v)

        # If there is a node with multiple parents
        if multiple_parent_node > 0:
            return [multiple_parent_node, cycle_edge[1]] if cycle_edge else [multiple_parent_node, cycle_edge[0]]

        # If there is a cycle
        return cycle_edge

