class Solution(object):
    def cherryPickup(self, grid):
        """
        :type grid: List[List[int]]
        :rtype: int
        """
        n = len(grid)

        # Create a memoization table to store results of subproblems
        memo = {}

        def dfs(x1, y1, x2):
            # If out of bounds or blocked, return -∞
            if x1 < 0 or y1 < 0 or x2 < 0 or y2 < 0 or grid[x1][y1] == -1 or grid[x2][y2] == -1:
                return float('-inf')

            # If we reach the bottom-right corner from both paths
            if x1 == n - 1 and y1 == n - 1 and x2 == n - 1 and y2 == n - 1:
                return grid[x1][y1]

            # If we have already computed the result for this state
            if (x1, y1, x2) in memo:
                return memo[(x1, y1, x2)]

            # Calculate the maximum cherries we can collect
            cherries = 0
            if x1 == x2:
                cherries += grid[x1][y1]
            else:
                cherries += grid[x1][y1] + grid[x2][y2]

            # Explore all possible moves from (x1, y1) to (x2, y2)
            max_cherries = 0
            for dx1 in [-1, 0]:
                for dy1 in [-1, 0]:
                    for dx2 in [-1, 0]:
                        for dy2 in [-1, 0]:
                            if dx1 != 0 or dy1 != 0 or dx2 != 0 or dy2 != 0:
                                max_cherries = max(max_cherries, dfs(x1 + dx1, y1 + dy1, x2 + dx2, y2 + dy2))

            # Store the result in the memoization table
            memo[(x1, y1, x2)] = cherries + max_cherries
            return memo[(x1, y1, x2)]

        # Start the DFS from the top-left corner to the bottom-right corner
        return dfs(0, 0, 0, 0)

