class Solution(object):
    def canCross(self, stones):
        """
        :type stones: List[int]
        :rtype: bool
        """
        n = len(stones)
        dp = [set() for _ in range(n)]
        dp[0].add(0)

        for i in range(1, n):
            for j in range(i):
                diff = stones[i] - stones[j]
                if diff > dp[j]: break
                if diff in dp[j]:
                    dp[i].add(diff - 1)
                    dp[i].add(diff)
                    dp[i].add(diff + 1)

        return any(1 in s for s in dp[-1])

