class Solution(object):
    def minDistance(self, word1, word2):
        """
        :type word1: str
        :type word2: str
        :rtype: int
        """
        # Initialize a 2D array to store the minimum edit distance
        m, n = len(word1), len(word2)
        dp = [[0] * (n + 1) for _ in range(m + 1)]

        # Fill the DP table
        for i in range(m + 1):
            dp[i][0] = i  # If word1 is empty, insert all characters from word2
        for j in range(n + 1):
            dp[0][j] = j  # If word2 is empty, delete all characters from word1

        for i in range(1, m + 1):
            for j in range(1, n + 1):
                if word1[i - 1] == word2[j - 1]:
                    dp[i][j] = dp[i - 1][j - 1]  # No operation needed
                else:
                    # Choose the minimum of insert, delete, and replace
                    dp[i][j] = 1 + min(dp[i - 1][j],  # Delete from word1
                                     dp[i][j - 1],  # Insert into word1
                                     dp[i - 1][j - 1])  # Replace in word1

        # The bottom-right cell contains the minimum edit distance
        return dp[m][n]

