class Solution(object):
    def reversePairs(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        if not nums:
            return 0

        # Function to perform merge sort and count reverse pairs
        def merge_sort(arr, left, right):
            if left >= right:
                return 0

            mid = (left + right) // 2
            inv_count = merge_sort(arr, left, mid) + merge_sort(arr, mid + 1, right)

            # Count reverse pairs during merge step
            j = mid + 1
            for i in range(left, mid + 1):
                while j <= right and arr[i] > 2 * arr[j]:
                    j += 1
                inv_count += j - (mid + 1)

            # Merge sorted subarrays
            merged = []
            i, j = left, mid + 1
            while i <= mid and j <= right:
                if arr[i] <= arr[j]:
                    merged.append(arr[i])
                    i += 1
                else:
                    merged.append(arr[j])
                    j += 1
            while i <= mid:
                merged.append(arr[i])
                i += 1
            while j <= right:
                merged.append(arr[j])
                j += 1

            # Copy merged array back to original array
            arr[left:right+1] = merged

            return inv_count

        return merge_sort(nums, 0, len(nums) - 1)

