class Solution(object):
    def reachingPoints(self, sx, sy, tx, ty):
        """
        :type sx: int
        :type sy: int
        :type tx: int
        :type ty: int
        :rtype: bool
        """
        while tx >= sx and ty >= sy:
            if tx > ty:
                if ty == sy:
                    # If ty == sy, we need to make sure tx is a multiple of (ty - sy)
                    if (tx - sx) % (ty - sy) == 0:
                        return True
                    else:
                        return False
                else:
                    # If tx > ty, we can reduce tx by subtracting the largest multiple of (ty - sy) less than or equal to tx
                    tx %= (ty - sy)
            else:
                if tx == sx:
                    # If tx == sx, we need to make sure ty is a multiple of (tx - sx)
                    if (ty - sy) % (tx - sx) == 0:
                        return True
                    else:
                        return False
                else:
                    # If ty > tx, we can reduce ty by subtracting the largest multiple of (tx - sx) less than or equal to ty
                    ty %= (tx - sx)

        # If we reach here, it means we couldn't transform sx, sy to tx, ty
        return False

