from collections import Counter

class Solution(object):
    def minStickers(self, stickers, target):
        """
        :type stickers: List[str]
        :type target: str
        :rtype: int
        """

        # Helper function to count the frequency of characters in a string
        def count(word):
            return Counter(word)

        # Initialize the DP table with a large number
        dp = {target: float('inf')}

        # Iterate over each sticker
        for sticker in stickers:
            sticker_count = count(sticker)

            # Create a new DP table to store the minimum stickers for each prefix
            new_dp = {}

            # Iterate over each prefix in the current DP table
            for prefix, num_stickers in dp.items():
                new_prefix_count = count(prefix)

                # Update the new DP table with the minimum number of stickers
                for char in new_prefix_count:
                    if char in sticker_count:
                        new_prefix_count[char] -= sticker_count[char]

                # If the new prefix is empty, update the minimum stickers
                if not new_prefix_count:
                    new_dp[prefix] = min(new_dp.get(prefix, float('inf')), num_stickers)
                else:
                    new_dp[prefix] = min(new_dp.get(prefix, float('inf')), num_stickers + 1)

            # Update the DP table
            dp = new_dp

        # Return the result for the target, or -1 if it's not possible
        return dp.get(target, -1)

