    def strangePrinter(self, s):
        """
        :type s: str
        :rtype: int
        """
        n = len(s)
        # Create a DP table with dimensions (n+1) x (n+1)
        dp = [[0] * (n + 1) for _ in range(n + 1)]

        # Iterate over all possible lengths of substrings
        for length in range(1, n + 1):
            for i in range(n - length + 1):
                j = i + length - 1
                if i == j:
                    # Base case: single character
                    dp[i][j] = 1
                else:
                    # Initialize the minimum turns as the maximum possible value
                    dp[i][j] = float('inf')

                    # Try splitting the substring into two parts
                    for k in range(i, j):
                        # If the characters at the start and end of the substring are the same,
                        # we can merge the two parts into one
                        if s[i] == s[j]:
                            dp[i][j] = min(dp[i][j], dp[i][k] + dp[k + 1][j])
                        else:
                            dp[i][j] = min(dp[i][j], dp[i][k] + dp[k + 1][j] + 1)

        # The result is stored in dp[0][n-1]
        return dp[0][n - 1]

