from collections import defaultdict

class Solution(object):
    def numDecodings(self, s):
        """
        :type s: str
        :rtype: int
        """
        MOD = 10**9 + 7

        # Initialize DP table
        dp = defaultdict(int)
        dp[0] = 1

        # Iterate through each character in the string
        for i in range(len(s)):
            if s[i] == '0':
                # If the current character is '0', we need to check the previous character
                if i > 0 and s[i - 1] == '1' or s[i - 1] == '2':
                    dp[i + 1] += dp[i - 1]
                else:
                    return 0  # Invalid encoding
            elif s[i] == '*':
                # If the current character is '*', it can represent any digit from 1 to 9
                dp[i + 1] += dp[i] * 9  # Multiply by 9 for '1*' to '9*'

                if i > 0:
                    prev_digit = s[i - 1]
                    if prev_digit == '1':
                        dp[i + 1] += dp[i - 1] * 9  # Multiply by 9 for '11*' to '19*'
                    elif prev_digit == '2':
                        dp[i + 1] += dp[i - 1] * 6  # Multiply by 6 for '21*' to '26*'
            else:
                # If the current character is a digit, it can only represent itself
                dp[i + 1] += dp[i]

            # Update the DP table with the modulo operation
            dp[i + 1] %= MOD

        return dp[len(s)]

