from typing import List

class Solution:
    def intersectionSizeTwo(self, intervals: List[List[int]]) -> int:
        # Sort intervals by their ending points
        intervals.sort(key=lambda x: x[1])

        # Initialize the result set with the last two elements of the first interval
        result = [intervals[0][1] - 1, intervals[0][1]]

        for i in range(1, len(intervals)):
            # Check if the current interval overlaps with the last element in the result
            if intervals[i][0] > result[-1]:
                # If it doesn't overlap, add the second last and the current interval's end
                result.append(result[-2])
                result.append(intervals[i][1])
            elif intervals[i][0] > result[-2]:
                # If it overlaps but not with the last element, add only the current interval's end
                result.append(intervals[i][1])

        return len(result)

