class Solution(object):
    def longestValidParentheses(self, s):
        """
        :type s: str
        :rtype: int
        """
        stack = []
        max_length = 0

        # Initialize the stack with a -1 to handle edge cases
        stack.append(-1)

        for i in range(len(s)):
            if s[i] == '(':
                # Push the index of the current opening parenthesis onto the stack
                stack.append(i)
            else:
                # If the stack is not empty, pop the top index
                if stack:
                    stack.pop()
                # If the stack is empty after popping, it means there's no matching opening parenthesis
                # So, push the current index onto the stack
                if not stack:
                    stack.append(i)
                # Calculate the length of the valid substring ending at the current index
                else:
                    max_length = max(max_length, i - stack[-1])

        return max_length

