class Solution(object):
    def findKthNumber(self, m, n, k):
        """
        :type m: int
        :type n: int
        :type k: int
        :rtype: int
        """

        # Helper function to count numbers less than or equal to target in the multiplication table
        def countLessThanOrEqualToTarget(target):
            count = 0
            for i in range(1, m + 1):
                count += min(target // i, n)
            return count

        # Binary search range for the kth smallest element
        left, right = 1, m * n
        while left < right:
            mid = (left + right) // 2
            if countLessThanOrEqualToTarget(mid) < k:
                left = mid + 1
            else:
                right = mid

        return left

