class Solution(object):
    def findMin(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        if not nums:
            return None

        left, right = 0, len(nums) - 1

        while left < right:
            mid = left + (right - left) // 2

            # If the middle element is equal to the rightmost element, skip the right half
            if nums[mid] == nums[right]:
                right -= 1
            # If the middle element is less than the rightmost element, the minimum is in the left half
            elif nums[mid] < nums[right]:
                right = mid
            # If the middle element is greater than the rightmost element, the minimum is in the right half
            else:
                left = mid + 1

        # When left equals right, we have found the minimum element
        return nums[left]

