class Solution(object):
    def solveSudoku(self, board):
        """
        :type board: List[List[str]]
        :rtype: None Do not return anything, modify board in-place instead.
        """

        def is_valid(board, row, col, num):
            # Check if num is already in the same row
            for i in range(9):
                if board[row][i] == str(num):
                    return False

            # Check if num is already in the same column
            for i in range(9):
                if board[i][col] == str(num):
                    return False

            # Check if num is already in the same 3x3 box
            start_row, start_col = 3 * (row // 3), 3 * (col // 3)
            for i in range(3):
                for j in range(3):
                    if board[start_row + i][start_col + j] == str(num):
                        return False

            return True

        def solve():
            for i in range(9):
                for j in range(9):
                    if board[i][j] == '.':
                        for num in range(1, 10):
                            if is_valid(board, i, j, num):
                                board[i][j] = str(num)

                                if solve():
                                    return True

                                # Backtrack if the current assignment does not lead to a solution
                                board[i][j] = '.'
                        return False

            return True

        solve()

