        """
        :type path: str
        :rtype: str
        """
        # Split the path by '/' and remove empty strings
        components = [component for component in path.split('/') if component]

        stack = []

        for component in components:
            if component == '..':
                if stack:
                    stack.pop()
            elif component != '.':
                stack.append(component)

        # Join the stack components with '/'
        return '/' + '/'.join(stack)

