class Solution(object):
    def numberOfArithmeticSlices(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        n = len(nums)
        if n < 3:
            return 0

        # Dictionary to store the count of subsequences for each difference and starting index
        dp = {}

        total_count = 0

        for i in range(1, n):
            for j in range(i):
                diff = nums[i] - nums[j]

                # Initialize the count for the current difference and starting index
                if diff not in dp:
                    dp[diff] = {}

                # If there's already a subsequence ending at index j with the same difference
                if j in dp[diff]:
                    # Add the number of subsequences ending at j with the same difference
                    total_count += dp[diff][j]
                    # Update the count for the current subsequence ending at i
                    dp[diff][i] = dp[diff].get(i, 0) + dp[diff][j] + 1

                # If there's no subsequence ending at j with the same difference
                else:
                    # Initialize the count for the current subsequence ending at i
                    dp[diff][i] = 1

        return total_count

