from collections import defaultdict

class TrieNode:
    def __init__(self):
        self.children = defaultdict(TrieNode)
        self.is_word = False

class Solution:
    def findAllConcatenatedWordsInADict(self, words):
        # Create a Trie from the list of words
        root = TrieNode()
        for word in words:
            self.insert(root, word)

        # Function to check if a word can be broken into smaller words
        def dfs(node, word, start):
            if start == len(word):
                return node.is_word
            for i in range(start, len(word)):
                child = node.children.get(word[i])
                if child:
                    if dfs(child, word, i + 1):
                        return True
            return False

        # Main function to find all concatenated words
        def find_concatenated_words():
            result = []
            for word in words:
                if dfs(root, word, 0):
                    result.append(word)
            return result

        return find_concatenated_words()

    def insert(self, root, word):
        current = root
        for char in word:
            current = current.children[char]
        current.is_word = True

