class Solution(object):
    def totalNQueens(self, n):
        """
        :type n: int
        :rtype: int
        """
        self.count = 0
        self.solveNQueens(n, 0)
        return self.count

    def solveNQueens(self, n, row):
        if row == n:
            self.count += 1
            return

        for col in range(n):
            if self.isSafe(row, col, n):
                self.placeQueen(row, col, n)
                self.solveNQueens(n, row + 1)
                self.removeQueen(row, col, n)

    def isSafe(self, row, col, n):
        # Check upper diagonal on left side
        i = row
        j = col
        while i >= 0 and j >= 0:
            if self.board[i][j] == 'Q':
                return False
            i -= 1
            j -= 1

        # Check lower diagonal on right side
        i = row
        j = col
        while i < n and j >= 0:
            if self.board[i][j] == 'Q':
                return False
            i += 1
            j -= 1

        # Check left side
        i = row
        j = col
        while j >= 0:
            if self.board[i][j] == 'Q':
                return False
            j -= 1

        return True

    def placeQueen(self, row, col, n):
        self.board[row][col] = 'Q'

    def removeQueen(self, row, col, n):
        self.board[row][col] = '.'

