class Solution(object):
    def solveNQueens(self, n):
        """
        :type n: int
        :rtype: List[List[str]]
        """
        self.res = []
        self.n = n
        self.dfs(0, [])
        return self.res

    def dfs(self, row, path):
        if row == self.n:
            self.res.append(path)
            return

        for col in range(self.n):
            if self.valid(row, col, path):
                self.dfs(row + 1, path + ['.' * col + 'Q' + '.' * (self.n - col - 1)])

    def valid(self, row, col, path):
        for r, c in enumerate(path):
            if c[col] == 'Q':
                return False
            if r - c.index('Q') == row - col:
                return False
            if r + c.index('Q') == row + col:
                return False
        return True
